def range_summary(nums):
    nums = sorted(list(set(nums)))
    result = []
    i = 0
    for j in range(1, len(nums)):
        if nums[i] == nums[j]:
            continue
        else:
            if i != j - 1:
                result.append(f"{nums[i]}")
            if nums[i] < nums[j]:
                result.append(f"{nums[i]}-{nums[j]-1}")
            else:
                result.append(f"{nums[j]}-{nums[i]}")
            i = j
    if nums[-1] != i:
        result.append(f"{nums[i]}")
    return ",".join(result)
